(window.webpackJsonp=window.webpackJsonp||[]).push([[61],{688:function(t,n){t.exports='\x3c!-- \ntitle: 03-登录注册开发\nsort: \n--\x3e \n\n## 实现登录\n\n> 使用bctypt验证密码hash值\n\n```go\nfunc Login(ctx *gin.Context) {\n\tDB := database.GetDB()\n\tname := ctx.PostForm("name")\n\tpassword := ctx.PostForm("password")\n\tlog.Print(name, password)\n\t// 数据处理\n\tvar user model.User\n\tDB.Where("name = ?", name).First(&user)\n\tif user.ID == 0 {\n\t\tctx.JSON(422, gin.H{\n\t\t\t"code": 422, "msg": "用户名不存在",\n\t\t})\n\t\treturn\n\t}\n\tif err := bcrypt.CompareHashAndPassword([]byte(user.Password), []byte(password)); err != nil {\n\t\tctx.JSON(400, gin.H{\n\t\t\t"code": 400, "msg": "密码错误",\n\t\t})\n\t\treturn\n\t}\n\n\ttoken := "Login Success"\n\n\tctx.JSON(200, gin.H{\n\t\t"code": 200,\n\t\t"data": gin.H{"token": token},\n\t\t"msg":  "登录成功",\n\t})\n}\n```\n\n## Token\n\n> JWT生成解析Token\n\n```go\npackage middleware\n\nimport (\n\t"time"\n\n\t"goLearn/model"\n\n\t"github.com/dgrijalva/jwt-go"\n)\n\n// token加密用的密钥\nvar jwtKey = []byte("fzf_secretca")\n\n// 自定义有效载荷(这里采用自定义的Name和Email作为有效载荷的一部分)\ntype Claims struct {\n\tUserID uint\n\tjwt.StandardClaims\n}\n\n// 调用jwt-go库生成token\nfunc ReleaseToken(user model.User) (string, error) {\n\t// 超时时间\n\texpirationTime := time.Now().Add(7 * 24 * time.Hour)\n\tclaims := &Claims{\n\t\tUserID: user.ID,\n\t\tStandardClaims: jwt.StandardClaims{\n\t\t\tExpiresAt: expirationTime.Unix(),\n\t\t\tIssuedAt:  time.Now().Unix(),\n\t\t\tIssuer:    "fzf404.top",\n\t\t\tSubject:   "user token",\n\t\t},\n\t}\n\n\t// 编码算法jwt.SigningMethodHS256, 返回token结构体指针\n\ttoken := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)\n    // 密钥加密token\n\ttokenString, err := token.SignedString(jwtKey)\n\tif err != nil {\n\t\treturn "", err\n\t}\n\treturn tokenString, nil\n}\n\n// token解码\nfunc ParseToken(tokenString string) (*jwt.Token, *Claims, error) {\n\tclaims := &Claims{}\n\tvar token *jwt.Token\n\tvar err error\n\t// 自定义的Claims结构体 ,token ,自定义函数来解析token-return之前定义好的签名\n\ttoken, err = jwt.ParseWithClaims(tokenString, claims, func(token *jwt.Token) (i interface{}, err error) {\n\t\treturn jwtKey, nil\n\t})\n\n\treturn token, claims, err\n}\n```\n\n## 验证Token\n\n> 中间件验证Token\n\n```go\npackage middleware\n\nimport (\n\t"net/http"\n\t"strings"\n\n\t"goLearn/database"\n\t"goLearn/model"\n\n\t"github.com/gin-gonic/gin"\n)\n\n// 返回处理函数\nfunc AuthMiddleware() gin.HandlerFunc {\n\treturn func(ctx *gin.Context) {\n\t\ttokenString := ctx.GetHeader("Authorization")\n\t\t// 判断Bearer\n\t\tif tokenString == "" || !strings.HasPrefix(tokenString, "Bearer") {\n\t\t\tctx.JSON(http.StatusUnauthorized, gin.H{\n\t\t\t\t"code": 401, "msg": "Token验证失败",\n\t\t\t})\n\t\t\tctx.Abort()\n\t\t\treturn\n\t\t}\n\t\t// 调用解析函数\n\t\ttokenString = tokenString[7:]\n\t\ttoken, Claims, err := ParseToken(tokenString)\n\n\t\t// 判断token是否有效\n\t\tif err != nil || !token.Valid {\n\t\t\tctx.JSON(http.StatusUnauthorized, gin.H{\n\t\t\t\t"code": 401, "msg": "Token失效，请重新登录", "data": err,\n\t\t\t})\n\t\t\tctx.Abort()\n\t\t\treturn\n\t\t}\n\t\t// 数据库查表\n\t\tuserId := Claims.UserID\n\t\tDB := database.GetDB()\n\t\tvar user model.User\n\t\tDB.First(&user, userId)\n\t\tif user.ID == 0 {\n\t\t\tctx.JSON(http.StatusUnauthorized, gin.H{\n\t\t\t\t"code": 401, "msg": "用户不存在",\n\t\t\t})\n\t\t\tctx.Abort()\n\t\t\treturn\n\t\t}\n\t\t// 用户存在 写入上下文\n\t\tctx.Set("user", user)\n\t\tctx.Set("name", user.Name)\n\t\tctx.Next()\n\t}\n}\n```\n\n## 独立配置文件\n\n> `config.go`\n\n```go\npackage config\n\nimport (\n\t"os"\n\n\t"github.com/spf13/viper"\n)\n\nfunc InitConfig() {\n\t// 当前路径\n\tworkDir, _ := os.Getwd()\n\t// config信息\n\tviper.SetConfigName("config")\n\tviper.SetConfigType("yml")\n\tviper.AddConfigPath(workDir + "/config")\n\t// 读取\n\terr := viper.ReadInConfig()\n\tif err != nil {\n\t\tpanic(err)\n\t}\n}\n```'}}]);